import React, { useState, useEffect } from 'react';
import { getUrunler, fiyatHesapla } from '../services/api';

const OLCU_LABEL = {
  GENISLIK:   'Genişlik W (mm)',
  YUKSEKLIK:  'Yükseklik H (mm)',
  UZUNLUK:    'Uzunluk L (mm)',
  CAP:        'Çap Ø (mm)',
  KASA_WH:    'Kasa W×H (mm)',
  BOGAZ_WH:   'Boğaz W×H (mm)',
  BOGAZ_CAP:  'Boğaz Çap (mm)',
  NETIC_CAP:  'Netice Çap (mm)',
  KASA_CAP:   'Kasa Çap (mm)',
  SLOT_SAYISI:'Slot Sayısı',
};

const OZELLIK_LABEL = {
  CERCEVE_TIPI:  'Çerçeve Tipi',
  MENFEZ_TIPI:   'Menfez Tipi',
  DAMPER_TIPI:   'Damper Tipi',
  RAL:           'RAL / Renk',
  MONTAJ:        'Montaj',
  AKSESUAR_TIPI: 'Aksesuar',
};

const KATEGORI_LABEL = {
  MENFEZ:          'Menfez',
  SLOT:            'Slot / Lineer',
  DIKDORTGEN_DAMPER: 'Dikdörtgen Damper',
  DAIRESEL_DAMPER: 'Dairesel Damper',
  KARE_ANENOSTAD:  'Kare Anemöstad',
  DAIRESEL_ANENOSTAD: 'Dairesel Anemöstad',
  KARE_SWIRL:      'Kare Swirl',
  DAIRESEL_SWIRL:  'Dairesel Swirl',
  PANJUR:          'Panjur',
  KAPAK:           'Kapak',
  KUTU:            'Kutu / Box',
};

export default function UrunSecimModal({ onEkle, onClose }) {
  const [urunler, setUrunler]       = useState([]);
  const [kategoriler, setKategoriler] = useState([]);
  const [aktifKat, setAktifKat]     = useState('');
  const [seciliUrun, setSeciliUrun] = useState(null);
  const [olcular, setOlcular]       = useState({});
  const [ozellikler, setOzellikler] = useState({});
  const [sonuc, setSonuc]           = useState(null);
  const [loading, setLoading]       = useState(false);
  const [hata, setHata]             = useState('');
  const [adet, setAdet]             = useState(1);
  const [aramaText, setAramaText]   = useState('');

  useEffect(() => {
    getUrunler().then(r => {
      setUrunler(r.data);
      const katlar = [...new Set(r.data.map(u => u.kategori))];
      setKategoriler(katlar);
      setAktifKat(katlar[0] || '');
    });
  }, []);

  const filtreliUrunler = urunler.filter(u =>
    (!aktifKat || u.kategori === aktifKat) &&
    (!aramaText || u.ad.toLowerCase().includes(aramaText.toLowerCase()))
  );

  const urunSec = (u) => {
    setSeciliUrun(u);
    setOlcular({});
    setOzellikler({});
    setSonuc(null);
    setHata('');
    setAdet(1);
  };

  const setOlcu = (tip, val) => setOlcular(o => ({ ...o, [tip]: val }));
  const setOzellik = (tip, val, multi) => {
    if (multi) {
      setOzellikler(o => {
        const mevcut = o[tip] || [];
        return {
          ...o,
          [tip]: mevcut.includes(val)
            ? mevcut.filter(x => x !== val)
            : [...mevcut, val],
        };
      });
    } else {
      setOzellikler(o => ({ ...o, [tip]: val }));
    }
  };

  const hesapla = async () => {
    if (!seciliUrun) return;
    setLoading(true); setHata(''); setSonuc(null);
    try {
      // Ölçüleri sayıya çevir
      const olcularNum = {};
      for (const [k, v] of Object.entries(olcular)) {
        const n = parseFloat(v);
        if (!isNaN(n)) olcularNum[k] = n;
      }
      const r = await fiyatHesapla(seciliUrun.kod, {
        olcular: olcularNum,
        ozellikler,
      });
      setSonuc(r.data);
    } catch (e) {
      setHata(e.response?.data?.hata || 'Fiyat hesaplanamadı. Ölçüleri kontrol edin.');
    } finally {
      setLoading(false);
    }
  };

  const kalemeEkle = () => {
    if (!sonuc || !seciliUrun) return;
    // Özellik özetini ürün adına ekle
    const ozetParcalar = [];
    for (const [tip, val] of Object.entries(ozellikler)) {
      if (val && val.length > 0) {
        const deger = Array.isArray(val) ? val.join(', ') : val;
        ozetParcalar.push(deger);
      }
    }
    const olcuOzet = Object.entries(olcular)
      .filter(([, v]) => v)
      .map(([k, v]) => `${OLCU_LABEL[k]?.split(' ')[0] || k}:${v}`)
      .join(' ');

    const tamAd = [seciliUrun.ad, olcuOzet, ...ozetParcalar].filter(Boolean).join(' | ');

    onEkle({
      urunKodu:   seciliUrun.kod,
      urunAdi:    tamAd,
      adet,
      birim:      'Adet',
      birimFiyat: sonuc.toplam,
      iskonto:    0,
    });
  };

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div style={{
        background: 'var(--surface)', border: '1px solid var(--border)',
        borderRadius: 14, width: '95%', maxWidth: 1050,
        maxHeight: '92vh', display: 'flex', flexDirection: 'column',
        animation: 'slideUp .2s ease',
      }}>
        {/* Header */}
        <div className="modal-header">
          <h2 style={{ fontFamily: 'var(--font-head)' }}>Ürün Seç & Fiyat Hesapla</h2>
          <button className="close-btn" onClick={onClose}>×</button>
        </div>

        <div style={{ display: 'flex', flex: 1, overflow: 'hidden' }}>

          {/* SOL: Ürün listesi */}
          <div style={{
            width: 300, flexShrink: 0, borderRight: '1px solid var(--border)',
            display: 'flex', flexDirection: 'column', overflow: 'hidden',
          }}>
            {/* Arama */}
            <div style={{ padding: '12px 16px', borderBottom: '1px solid var(--border)' }}>
              <input
                className="input" placeholder="🔍 Ürün ara..."
                value={aramaText} onChange={e => setAramaText(e.target.value)}
                style={{ fontSize: 13 }}
              />
            </div>

            {/* Kategori tabları */}
            <div style={{ overflowY: 'auto', flex: 1 }}>
              {kategoriler.map(k => (
                <div key={k}>
                  <div
                    onClick={() => setAktifKat(aktifKat === k ? '' : k)}
                    style={{
                      padding: '8px 16px', cursor: 'pointer',
                      fontSize: 11, fontWeight: 700, letterSpacing: '.06em',
                      textTransform: 'uppercase', color: 'var(--muted)',
                      background: 'var(--surface)',
                      borderBottom: '1px solid var(--border)',
                      display: 'flex', justifyContent: 'space-between',
                    }}
                  >
                    <span>{KATEGORI_LABEL[k] || k}</span>
                    <span style={{ color: 'var(--border)' }}>{aktifKat === k ? '▲' : '▼'}</span>
                  </div>
                  {(aktifKat === k || aramaText) && filtreliUrunler
                    .filter(u => u.kategori === k)
                    .map(u => (
                      <div
                        key={u.kod}
                        onClick={() => urunSec(u)}
                        style={{
                          padding: '10px 20px', cursor: 'pointer', fontSize: 13,
                          background: seciliUrun?.kod === u.kod ? 'var(--surface2)' : 'transparent',
                          borderLeft: seciliUrun?.kod === u.kod ? '2px solid var(--accent)' : '2px solid transparent',
                          color: seciliUrun?.kod === u.kod ? 'var(--text)' : 'var(--muted)',
                          borderBottom: '1px solid var(--border)',
                        }}
                        onMouseEnter={e => { if (seciliUrun?.kod !== u.kod) e.currentTarget.style.background = 'var(--surface2)'; }}
                        onMouseLeave={e => { if (seciliUrun?.kod !== u.kod) e.currentTarget.style.background = 'transparent'; }}
                      >
                        {u.ad}
                      </div>
                    ))}
                </div>
              ))}
            </div>
          </div>

          {/* SAĞ: Form + sonuç */}
          <div style={{ flex: 1, overflow: 'auto', padding: 24 }}>
            {!seciliUrun && (
              <div style={{ textAlign: 'center', color: 'var(--muted)', marginTop: 60, fontSize: 14 }}>
                ← Soldan bir ürün seçin
              </div>
            )}

            {seciliUrun && (
              <>
                <div style={{ marginBottom: 20 }}>
                  <div style={{ fontFamily: 'var(--font-head)', fontSize: 18, fontWeight: 700 }}>{seciliUrun.ad}</div>
                  <div style={{ fontSize: 12, color: 'var(--muted)', marginTop: 3 }}>{seciliUrun.kod}</div>
                </div>

                {/* Ölçüler */}
                {seciliUrun.zorunluOlcular.length > 0 && (
                  <div style={{ marginBottom: 20 }}>
                    <div style={{ fontSize: 12, color: 'var(--muted)', letterSpacing: '.08em', textTransform: 'uppercase', marginBottom: 10, fontWeight: 600 }}>Ölçüler</div>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(160px,1fr))', gap: 12 }}>
                      {seciliUrun.zorunluOlcular.map(olcu => (
                        <div key={olcu}>
                          <label>{OLCU_LABEL[olcu] || olcu}</label>
                          <input
                            className="input" type="number" placeholder="mm"
                            value={olcular[olcu] || ''}
                            onChange={e => setOlcu(olcu, e.target.value)}
                          />
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                {/* Özellikler */}
                {Object.keys(seciliUrun.ozellikler).length > 0 && (
                  <div style={{ marginBottom: 20 }}>
                    <div style={{ fontSize: 12, color: 'var(--muted)', letterSpacing: '.08em', textTransform: 'uppercase', marginBottom: 10, fontWeight: 600 }}>Özellikler</div>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px,1fr))', gap: 16 }}>
                      {Object.entries(seciliUrun.ozellikler).map(([tip, secenekler]) => {
                        const isMulti = seciliUrun.multiSelectOzellikler.includes(tip);
                        const secili = ozellikler[tip];
                        return (
                          <div key={tip}>
                            <label>{OZELLIK_LABEL[tip] || tip}{isMulti && ' (çoklu)'}</label>
                            {isMulti ? (
                              <div style={{ display: 'flex', flexDirection: 'column', gap: 5 }}>
                                {secenekler.map(s => (
                                  <label key={s} style={{
                                    display: 'flex', alignItems: 'center', gap: 8,
                                    cursor: 'pointer', textTransform: 'none',
                                    letterSpacing: 0, fontWeight: 400, color: 'var(--text)',
                                    fontSize: 13,
                                  }}>
                                    <input type="checkbox"
                                      checked={Array.isArray(secili) && secili.includes(s)}
                                      onChange={() => setOzellik(tip, s, true)}
                                    />
                                    {s}
                                  </label>
                                ))}
                              </div>
                            ) : (
                              <select className="select" value={secili || ''} onChange={e => setOzellik(tip, e.target.value, false)}>
                                <option value="">— Seç —</option>
                                {secenekler.map(s => <option key={s} value={s}>{s}</option>)}
                              </select>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                )}

                {/* Hesapla butonu */}
                <button
                  className="btn btn-secondary"
                  onClick={hesapla}
                  disabled={loading}
                  style={{ marginBottom: 16 }}
                >
                  {loading ? 'Hesaplanıyor...' : '🧮 Fiyat Hesapla'}
                </button>

                {hata && (
                  <div style={{ color: 'var(--red)', fontSize: 13, marginBottom: 12, background: '#ef444410', padding: '10px 14px', borderRadius: 8 }}>
                    ⚠️ {hata}
                  </div>
                )}

                {/* Sonuç */}
                {sonuc && (
                  <div style={{ background: 'var(--surface2)', borderRadius: 10, padding: 20, border: '1px solid var(--border)' }}>
                    <div style={{ fontFamily: 'var(--font-head)', fontWeight: 700, marginBottom: 14, fontSize: 15 }}>Hesaplama Sonucu</div>
                    {[
                      ['Ham Fiyat',   sonuc.hamFiyat],
                      ['Oran Ekleri', sonuc.oranEkleri],
                      ['Motor Ek',    sonuc.motorEk],
                    ].map(([lbl, val]) => val > 0 && (
                      <div key={lbl} style={{ display: 'flex', justifyContent: 'space-between', padding: '4px 0', fontSize: 13, color: 'var(--muted)' }}>
                        <span>{lbl}</span>
                        <span>{val.toLocaleString('tr-TR', { minimumFractionDigits: 2 })} ₺</span>
                      </div>
                    ))}
                    <div style={{ display: 'flex', justifyContent: 'space-between', padding: '10px 0 6px', borderTop: '1px solid var(--border)', fontWeight: 700, color: 'var(--accent)', fontSize: 16, marginTop: 6 }}>
                      <span>Birim Fiyat</span>
                      <span>{sonuc.toplam.toLocaleString('tr-TR', { minimumFractionDigits: 2 })} ₺</span>
                    </div>

                    {/* Adet + Ekle */}
                    <div style={{ display: 'flex', gap: 12, marginTop: 16, alignItems: 'center' }}>
                      <div style={{ flex: 1 }}>
                        <label>Adet</label>
                        <input className="input" type="number" min="1" value={adet} onChange={e => setAdet(parseInt(e.target.value) || 1)} />
                      </div>
                      <div style={{ flex: 2, display: 'flex', alignItems: 'flex-end' }}>
                        <button className="btn btn-primary" style={{ width: '100%', justifyContent: 'center', padding: '10px' }} onClick={kalemeEkle}>
                          + Kaleme Ekle ({(sonuc.toplam * adet).toLocaleString('tr-TR', { minimumFractionDigits: 2 })} ₺)
                        </button>
                      </div>
                    </div>
                  </div>
                )}
              </>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
